package org.jetbrains.letsPlot.core.plot.base.render.text

internal data class VectorGlyph(
    val advanceEm: Double,   // horizontal advance, em units (1.0 == 1 em)
    val pathData: String?    // SVG path-data, em units * 1000; null for blank glyphs (e.g. space)
)

internal object LatexVectorFont {
    // Per-glyph design coordinates are in this UPM. The renderer scales by fontSize/UPM.
    const val UPM: Int = 1000

    // Word-wrapping can inject '\n'/'\t'/'\r' inside a formula; register them as zero-advance blanks
    // so they're ignored and the formula doesn't fall back to the legacy tspan renderer.
    // TODO: remove once wrap() is LaTeX-aware and never injects whitespace other than ' ' into a formula.
    private val WHITESPACE_GLYPH = VectorGlyph(advanceEm = 0.0, pathData = null)

    private val GLYPHS: Map<Char, VectorGlyph> = buildLatexGlyphTable() +
            mapOf('\n' to WHITESPACE_GLYPH, '\t' to WHITESPACE_GLYPH, '\r' to WHITESPACE_GLYPH)

    fun isSupported(char: Char): Boolean = GLYPHS.containsKey(char)
    fun isSupported(text: String): Boolean = text.all(::isSupported)
    fun glyphOrNull(char: Char): VectorGlyph? = GLYPHS[char]
    fun advanceEm(char: Char): Double =
        GLYPHS[char]?.advanceEm ?: error("vector advance requested for unsupported char: U+${char.code.toString(16).padStart(4, '0').uppercase()}")
}

